module RefModule( max, q, clk, rst ) ;parameter   size_cnt = 8 ;
    input   [size_cnt-1:0]          max ;
    output                          q ;
    input                           clk ;
    input                           rst ;
    reg                             q ;

    reg     [size_cnt-1:0]          obf_cnt ;


    always  @( posedge clk or posedge rst )
        if ( rst )
            obf_cnt <= 0 ;
        else
            if ( obf_cnt == 0 )
                obf_cnt <= max ;                        
            else
                obf_cnt <= obf_cnt - 1 ;


    always  @( posedge clk )
        if ( obf_cnt == 1 )
            q <= 'b1 ;
        else
            q <= 'b0 ;endmodule
